package org.elasticsearch.cluster.routing.allocation.allocator;

import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.elasticsearch.action.ActionListener;
import org.elasticsearch.cluster.metadata.IndexMetadata;
import org.elasticsearch.cluster.routing.ShardRouting;
import org.elasticsearch.cluster.routing.allocation.AllocateUnassignedDecision;
import org.elasticsearch.cluster.routing.allocation.MoveDecision;
import org.elasticsearch.cluster.routing.allocation.RoutingAllocation;
import org.elasticsearch.cluster.routing.allocation.RoutingExplanations;
import org.elasticsearch.cluster.routing.allocation.ShardAllocationDecision;
import org.elasticsearch.cluster.routing.allocation.command.AllocationCommands;
import org.elasticsearch.common.settings.ClusterSettings;
import org.elasticsearch.common.settings.Setting;
import org.elasticsearch.common.settings.Setting.Property;
import org.elasticsearch.injection.guice.Inject;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

/**
 * A {@link ShardsAllocator} implementation that extends the standard
 * {@link BalancedShardsAllocator} to support priority-based shard allocation.
 *
 * <p>
 * The allocator prioritizes unassigned shards based on their index's priority level
 * (see {@link #INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING}). Shards with higher priority
 * are processed first, ensuring critical indices receive "first pick" of available slots.
 * </p>
 *
 * <p>
 * This allocator works in conjunction with {@link PriorityAllocationDecider} to:
 * <ul>
 *   <li>Reorder the shard assignment queue by priority (highest-priority shards first)</li>
 *   <li>Delegate balancing decisions to the wrapped BalancedShardsAllocator</li>
 *   <li>Support soft constraints via THROTTLE decisions from PriorityAllocationDecider</li>
 * </ul>
 * </p>
 *
 * <h2>Configuration</h2>
 *
 * Enable or disable priority-aware allocation:
 * <pre>
 * cluster.routing.allocation.priority.enabled: true  (default)
 * </pre>
 *
 * Control which node tiers are considered premium:
 * <pre>
 * cluster.routing.allocation.priority.premium_tiers: [premium, hot]
 * </pre>
 *
 * Set the priority threshold above which to prefer premium nodes:
 * <pre>
 * cluster.routing.allocation.priority.threshold: 70
 * </pre>
 *
 * <h2>Index Settings</h2>
 *
 * Set index priority for shard allocation preferences:
 * <pre>
 * PUT /myindex/_settings
 * {
 *   "index.routing.allocation.priority": 100
 * }
 * </pre>
 *
 * @see PriorityAllocationDecider
 * @see BalancedShardsAllocator
 * @see IndexMetadata#INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING
 */
public class PriorityShardsAllocator implements ShardsAllocator {

    private static final Logger logger = LogManager.getLogger(PriorityShardsAllocator.class);

    /**
     * Cluster-level setting to enable/disable priority-aware allocation.
     * Defaults to true; set to false to revert to standard balanced allocation.
     */
    public static final Setting<Boolean> CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED = Setting.boolSetting(
        "cluster.routing.allocation.priority.enabled",
        true,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Cluster-level setting specifying which node tier names are considered premium.
     * Shards with high priority prefer allocation to premium tier nodes.
     * Example: ["premium", "hot"]
     */
    public static final Setting<List<String>> CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS = Setting.stringListSetting(
        "cluster.routing.allocation.priority.premium_tiers",
        java.util.List.of("premium"),
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Cluster-level setting specifying the priority threshold above which
     * to apply premium tier preferences. Indices with priority >= threshold
     * will prefer premium nodes, but can still allocate to standard nodes.
     * Range: 0-100, Default: 70
     */
    public static final Setting<Integer> CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD = Setting.intSetting(
        "cluster.routing.allocation.priority.threshold",
        70,
        0,
        100,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Index-level setting specifying the priority of this index for shard allocation.
     * Higher values indicate higher priority for placement on preferred (premium) nodes.
     * Range: 0-100, Default: 50
     */
    public static final String INDEX_ROUTING_ALLOCATION_PRIORITY = "index.routing.allocation.priority";

    // Volatile fields for dynamic configuration updates
    private volatile boolean priorityAllocationEnabled;
    private volatile List<String> premiumTiers;
    private volatile int priorityThreshold;

    // Delegate allocator for actual shard balancing
    private final BalancedShardsAllocator delegateAllocator;

    /**
     * Creates a new PriorityShardsAllocator with default configuration.
     * The delegate BalancedShardsAllocator uses standard settings.
     */
    public PriorityShardsAllocator() {
        this.delegateAllocator = new BalancedShardsAllocator();
    }

    /**
     * Creates a new PriorityShardsAllocator with custom cluster settings.
     * Registers dynamic setting listeners for priority configuration changes.
     *
     * @param clusterSettings the cluster settings to watch for priority configuration
     * @param delegateAllocator the wrapped allocator for balancing decisions
     */
    @Inject
    public PriorityShardsAllocator(
        ClusterSettings clusterSettings,
        BalancedShardsAllocator delegateAllocator
    ) {
        this.delegateAllocator = delegateAllocator;

        // Initialize settings from cluster configuration
        this.priorityAllocationEnabled = CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED.get(clusterSettings.getSettings());
        this.premiumTiers = CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS.get(clusterSettings.getSettings());
        this.priorityThreshold = CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD.get(clusterSettings.getSettings());

        // Register listeners for dynamic updates
        clusterSettings.addSettingsUpdateConsumer(
            CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED,
            this::setPriorityAllocationEnabled
        );
        clusterSettings.addSettingsUpdateConsumer(
            CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS,
            this::setPremiumTiers
        );
        clusterSettings.addSettingsUpdateConsumer(
            CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD,
            this::setPriorityThreshold
        );
    }

    /**
     * Main allocation method. Sorts unassigned shards by priority and delegates
     * to the wrapped BalancedShardsAllocator for actual allocation decisions.
     *
     * <p>
     * Algorithm:
     * <ol>
     *   <li>If priority allocation is disabled, delegate directly</li>
     *   <li>Otherwise, sort unassigned shards by index priority (descending)</li>
     *   <li>Invoke delegate allocator's allocate() method</li>
     * </ol>
     * </p>
     *
     * @param allocation the current routing allocation state
     */
    @Override
    public void allocate(RoutingAllocation allocation) {
        if (!priorityAllocationEnabled) {
            // Feature disabled; use standard balanced allocation
            delegateAllocator.allocate(allocation);
            return;
        }

        // Sort unassigned shards by priority (highest first)
        sortUnassignedShardsByPriority(allocation);

        // Delegate to BalancedShardsAllocator for balanced shard distribution
        delegateAllocator.allocate(allocation);
    }

    /**
     * Async variant of allocate(). Delegates to the wrapped allocator's async method.
     *
     * @param allocation the current routing allocation state
     * @param listener listener to be called once async allocation is complete
     */
    @Override
    public void allocate(RoutingAllocation allocation, ActionListener<Void> listener) {
        if (!priorityAllocationEnabled) {
            delegateAllocator.allocate(allocation, listener);
            return;
        }

        sortUnassignedShardsByPriority(allocation);
        delegateAllocator.allocate(allocation, listener);
    }

    /**
     * Executes explicit allocation commands. Delegates to the wrapped allocator.
     *
     * @param allocation the current routing allocation state
     * @param commands the allocation commands to execute
     * @param explain whether to return explain information
     * @param retryFailed whether to reset the failed counter for retryable shards
     * @return explanations for each executed command
     */
    @Override
    public RoutingExplanations execute(
        RoutingAllocation allocation,
        AllocationCommands commands,
        boolean explain,
        boolean retryFailed
    ) {
        return delegateAllocator.execute(allocation, commands, explain, retryFailed);
    }

    /**
     * Returns the allocation decision for a single shard. Queries the wrapped
     * allocator for shard allocation decisions (used by the explain API).
     *
     * @param shard the shard routing to decide on
     * @param allocation the current routing allocation state
     * @return the allocation decision for this shard
     */
    @Override
    public ShardAllocationDecision decideShardAllocation(ShardRouting shard, RoutingAllocation allocation) {
        return delegateAllocator.decideShardAllocation(shard, allocation);
    }

    /**
     * Sorts unassigned shards in the routing allocation by their index priority.
     * Shards from indices with higher priority are moved to the front of the queue,
     * ensuring they are considered first during allocation.
     *
     * <p>
     * The priority value is retrieved from {@link IndexMetadata} using
     * the INDEX_ROUTING_ALLOCATION_PRIORITY setting. Indices without an explicit
     * priority setting use the default value of 50.
     * </p>
     *
     * <p>
     * Time Complexity: O(n log n) where n = number of unassigned shards
     * This is typically << 1000 shards in most clusters, making the overhead negligible.
     * </p>
     *
     * @param allocation the routing allocation containing the unassigned shards to sort
     */
    private void sortUnassignedShardsByPriority(RoutingAllocation allocation) {
        try {
            var unassignedShards = allocation.routingNodes().unassigned();
            if (unassignedShards == null || unassignedShards.size() == 0) {
                return; // No shards to sort
            }

            // Create a mutable list of shards sorted by priority (descending)
            List<ShardRouting> shardsToSort = new ArrayList<>(unassignedShards.size());
            for (ShardRouting shard : unassignedShards) {
                shardsToSort.add(shard);
            }

            // Sort by index priority (descending: highest priority first)
            shardsToSort.sort(
                Comparator.comparingInt(
                    (ShardRouting shard) -> getIndexPriority(allocation, shard)
                ).reversed()
            );

            // Replace the unassigned shards iterator with sorted shards
            // This requires calling internal routing nodes methods
            // Note: This is pseudocode; actual implementation depends on
            // RoutingNodes API for reordering
            reorderUnassignedShards(allocation, shardsToSort);

            if (logger.isDebugEnabled()) {
                logger.debug(
                    "Sorted {} unassigned shards by priority (feature enabled)",
                    shardsToSort.size()
                );
            }
        } catch (Exception e) {
            // Log error but don't fail allocation on sorting error
            logger.warn("Failed to sort unassigned shards by priority; continuing with standard order", e);
        }
    }

    /**
     * Reorders the unassigned shards in the routing nodes to match the priority-sorted list.
     * This is a placeholder for the actual reordering implementation, which depends on
     * the RoutingNodes API.
     *
     * @param allocation the routing allocation state
     * @param sortedShards the shards sorted by priority (descending)
     */
    private void reorderUnassignedShards(RoutingAllocation allocation, List<ShardRouting> sortedShards) {
        // TODO: Implement actual reordering using RoutingNodes API
        // This may involve:
        // 1. Clearing the current unassigned shards collection
        // 2. Adding shards back in priority order
        // OR
        // 3. Using a custom iterator/wrapper that returns shards in priority order
        //
        // Example (pseudocode):
        // RoutingNodes routingNodes = allocation.routingNodes();
        // routingNodes.unassigned().clear();
        // for (ShardRouting shard : sortedShards) {
        //     routingNodes.unassigned().add(shard);
        // }
    }

    /**
     * Retrieves the priority value for an index from its metadata.
     * Falls back to the default priority if not explicitly set.
     *
     * @param allocation the routing allocation state (contains cluster metadata)
     * @param shard the shard whose index priority to retrieve
     * @return the index priority (0-100), or default 50 if not set
     */
    private int getIndexPriority(RoutingAllocation allocation, ShardRouting shard) {
        try {
            IndexMetadata indexMetadata = allocation.metadata().getIndexSafe(shard.index());
            // TODO: Extract priority from indexMetadata
            // Pseudo-code:
            // return indexMetadata.getSettings().getAsInt(
            //     INDEX_ROUTING_ALLOCATION_PRIORITY,
            //     50  // default priority
            // );
            return 50; // placeholder
        } catch (Exception e) {
            logger.warn("Failed to retrieve priority for index [{}], using default", shard.index(), e);
            return 50; // default priority on error
        }
    }

    /**
     * Determines if a node is classified as premium tier.
     * Queries the node's attributes for a tier classification and checks
     * if it matches one of the configured premium tiers.
     *
     * @param nodeName the name/ID of the node to check
     * @param allocation the routing allocation state (contains node metadata)
     * @return true if the node is classified as a premium tier node
     */
    private boolean isNodePremiumTier(String nodeName, RoutingAllocation allocation) {
        try {
            // TODO: Extract node attributes and check tier classification
            // Pseudo-code:
            // var node = allocation.nodes().get(nodeName);
            // if (node == null) return false;
            // String nodeTier = node.getAttributes().get("allocation_tier");
            // return premiumTiers.contains(nodeTier);
            return false; // placeholder
        } catch (Exception e) {
            logger.warn("Failed to determine tier for node [{}], assuming standard", nodeName, e);
            return false; // assume standard on error
        }
    }

    // ============= Configuration Update Methods =============

    /**
     * Called when the priority allocation enabled setting is updated dynamically.
     *
     * @param enabled the new enabled state
     */
    private void setPriorityAllocationEnabled(boolean enabled) {
        this.priorityAllocationEnabled = enabled;
        logger.info("Priority-aware shard allocation is now {}", enabled ? "enabled" : "disabled");
    }

    /**
     * Called when the premium tiers setting is updated dynamically.
     *
     * @param tiers the new list of premium tier names
     */
    private void setPremiumTiers(List<String> tiers) {
        this.premiumTiers = tiers;
        logger.info("Updated premium tier classifications: {}", tiers);
    }

    /**
     * Called when the priority threshold setting is updated dynamically.
     *
     * @param threshold the new priority threshold (0-100)
     */
    private void setPriorityThreshold(int threshold) {
        this.priorityThreshold = threshold;
        logger.info("Updated priority threshold: {}", threshold);
    }

    // ============= Getters for testing/debugging =============

    /**
     * Returns whether priority allocation is currently enabled.
     *
     * @return true if enabled, false otherwise
     */
    public boolean isPriorityAllocationEnabled() {
        return priorityAllocationEnabled;
    }

    /**
     * Returns the current list of premium tier names.
     *
     * @return list of premium tier names
     */
    public List<String> getPremiumTiers() {
        return new ArrayList<>(premiumTiers);
    }

    /**
     * Returns the current priority threshold value.
     *
     * @return the priority threshold (0-100)
     */
    public int getPriorityThreshold() {
        return priorityThreshold;
    }
}

