28: /**
29:  * Combines the decision of multiple {@link AllocationDecider} implementations into a single allocation decision.
30:  */
31: public class AllocationDeciders {
32: 
33:     private static final Logger logger = LogManager.getLogger(AllocationDeciders.class);
34: 
35:     private static final Decision NO_IGNORING_SHARD_FOR_NODE = Decision.single(
36:         Decision.Type.NO,
37:         "ignored_shards_for_node",
38:         "shard temporarily ignored for node due to earlier failure"
39:     );
40: 
41:     private final AllocationDecider[] deciders;
42: 
43:     public AllocationDeciders(Collection<? extends AllocationDecider> deciders) {
44:         this.deciders = deciders.toArray(AllocationDecider[]::new);
45:     }
46: 
47:     public Decision canAllocate(ShardRouting shardRouting, RoutingAllocation allocation) {
48:         return withDeciders(
49:             allocation,
50:             decider -> decider.canAllocate(shardRouting, allocation),
51:             (decider, decision) -> Strings.format("Can not allocate [%s] on any node. [%s]: %s", shardRouting, decider, decision)
52:         );
53:     }
54: 
55:     public Decision canAllocate(IndexMetadata indexMetadata, RoutingNode node, RoutingAllocation allocation) {
56:         return withDeciders(
57:             allocation,
58:             decider -> decider.canAllocate(indexMetadata, node, allocation),
59:             (decider, decision) -> Strings.format(
60:                 "Can not allocate [%s] on node [%s]. [%s]: %s",
61:                 indexMetadata.getIndex().getName(),
62:                 node.node(),
63:                 decider,
64:                 decision
65:             )
66:         );
67:     }
