69:     public Decision canAllocate(ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
70:         return withDecidersCheckingShardIgnoredNodes(
71:             allocation,
72:             shardRouting,
73:             node,
74:             decider -> decider.canAllocate(shardRouting, node, allocation),
75:             (decider, decision) -> Strings.format(
76:                 "Can not allocate [%s] on node [%s]. [%s]: %s",
77:                 shardRouting,
78:                 node.node(),
79:                 decider,
80:                 decision
81:             )
82:         );
83:     }
84: 
85:     public Decision canRebalance(RoutingAllocation allocation) {
86:         return withDeciders(
87:             allocation,
88:             decider -> decider.canRebalance(allocation),
89:             (decider, decision) -> Strings.format("Can not rebalance. [%s]: %s", decider, decision)
90:         );
91:     }
