159:         return withDecidersCheckingShardIgnoredNodes(
160:             allocation,
161:             shardRouting,
162:             node,
163:             decider -> decider.canAllocateReplicaWhenThereIsRetentionLease(shardRouting, node, allocation),
164:             (decider, decision) -> Strings.format(
