77:         "cluster.routing.allocation.awareness.attributes",
78:         Property.Dynamic,
79:         Property.NodeScope
80:     );
81: 
82:     private static final String FORCE_GROUP_SETTING_PREFIX = "cluster.routing.allocation.awareness.force.";
83: 
84:     public static final Setting<Settings> CLUSTER_ROUTING_ALLOCATION_AWARENESS_FORCE_GROUP_SETTING = Setting.groupSetting(
85:         FORCE_GROUP_SETTING_PREFIX,
86:         AwarenessAllocationDecider::validateForceAwarenessSettings,
87:         Property.Dynamic,
88:         Property.NodeScope
89:     );
