92: 
93:     private volatile Map<String, List<String>> forcedAwarenessAttributes;
94: 
95:     public AwarenessAllocationDecider(Settings settings, ClusterSettings clusterSettings) {
96:         this.awarenessAttributes = CLUSTER_ROUTING_ALLOCATION_AWARENESS_ATTRIBUTE_SETTING.get(settings);
97:         clusterSettings.addSettingsUpdateConsumer(CLUSTER_ROUTING_ALLOCATION_AWARENESS_ATTRIBUTE_SETTING, this::setAwarenessAttributes);
98:         setForcedAwarenessAttributes(CLUSTER_ROUTING_ALLOCATION_AWARENESS_FORCE_GROUP_SETTING.get(settings));
99:         clusterSettings.addSettingsUpdateConsumer(
100:             CLUSTER_ROUTING_ALLOCATION_AWARENESS_FORCE_GROUP_SETTING,
101:             this::setForcedAwarenessAttributes
102:         );
103:     }
