import org.elasticsearch.injection.guice.Inject;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

/**
 * A {@link ShardsAllocator} implementation that extends the standard
 * {@link BalancedShardsAllocator} to support priority-based shard allocation.
 *
 * <p>
 * The allocator prioritizes unassigned shards based on their index's priority level
 * (see {@link #INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING}). Shards with higher priority
 * are processed first, ensuring critical indices receive "first pick" of available slots.
 * </p>
 *
 * <p>
 * This allocator works in conjunction with {@link PriorityAllocationDecider} to:
 * <ul>
 *   <li>Reorder the shard assignment queue by priority (highest-priority shards first)</li>
 *   <li>Delegate balancing decisions to the wrapped BalancedShardsAllocator</li>
 *   <li>Support soft constraints via THROTTLE decisions from PriorityAllocationDecider</li>
 * </ul>
 * </p>
 *
 * <h2>Configuration</h2>
 *
 * Enable or disable priority-aware allocation:
 * <pre>
 * cluster.routing.allocation.priority.enabled: true  (default)
 * </pre>
 *
 * Control which node tiers are considered premium:
 * <pre>
 * cluster.routing.allocation.priority.premium_tiers: [premium, hot]
 * </pre>
 *
 * Set the priority threshold above which to prefer premium nodes:
 * <pre>
 * cluster.routing.allocation.priority.threshold: 70
 * </pre>
 *
 * <h2>Index Settings</h2>
 *
 * Set index priority for shard allocation preferences:
 * <pre>
 * PUT /myindex/_settings
 * {
 *   "index.routing.allocation.priority": 100
 * }
 * </pre>
 *
 * @see PriorityAllocationDecider
 * @see BalancedShardsAllocator
 * @see IndexMetadata#INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING
 */
public class PriorityShardsAllocator implements ShardsAllocator {

    private static final Logger logger = LogManager.getLogger(PriorityShardsAllocator.class);

    /**
     * Cluster-level setting to enable/disable priority-aware allocation.
     * Defaults to true; set to false to revert to standard balanced allocation.
     */
    public static final Setting<Boolean> CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED = Setting.boolSetting(
        "cluster.routing.allocation.priority.enabled",
        true,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Cluster-level setting specifying which node tier names are considered premium.
     * Shards with high priority prefer allocation to premium tier nodes.
     * Example: ["premium", "hot"]
     */
    public static final Setting<List<String>> CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS = Setting.stringListSetting(
        "cluster.routing.allocation.priority.premium_tiers",
        java.util.List.of("premium"),
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Cluster-level setting specifying the priority threshold above which
     * to apply premium tier preferences. Indices with priority >= threshold
     * will prefer premium nodes, but can still allocate to standard nodes.
     * Range: 0-100, Default: 70
     */
    public static final Setting<Integer> CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD = Setting.intSetting(
        "cluster.routing.allocation.priority.threshold",
        70,
        0,
        100,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Index-level setting specifying the priority of this index for shard allocation.
     * Higher values indicate higher priority for placement on preferred (premium) nodes.
     * Range: 0-100, Default: 50
     */
    public static final String INDEX_ROUTING_ALLOCATION_PRIORITY = "index.routing.allocation.priority";

    // Volatile fields for dynamic configuration updates
    private volatile boolean priorityAllocationEnabled;
    private volatile List<String> premiumTiers;
    private volatile int priorityThreshold;

    // Delegate allocator for actual shard balancing
    private final BalancedShardsAllocator delegateAllocator;

    /**
     * Creates a new PriorityShardsAllocator with default configuration.
     * The delegate BalancedShardsAllocator uses standard settings.
     */
    public PriorityShardsAllocator() {
        this.delegateAllocator = new BalancedShardsAllocator();
    }

    /**
     * Creates a new PriorityShardsAllocator with custom cluster settings.
     * Registers dynamic setting listeners for priority configuration changes.
     *
     * @param clusterSettings the cluster settings to watch for priority configuration
     * @param delegateAllocator the wrapped allocator for balancing decisions
     */
    @Inject
    public PriorityShardsAllocator(
        ClusterSettings clusterSettings,
        BalancedShardsAllocator delegateAllocator
    ) {
        this.delegateAllocator = delegateAllocator;

        // Initialize settings from cluster configuration
        this.priorityAllocationEnabled = CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED.get(clusterSettings.getSettings());
        this.premiumTiers = CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS.get(clusterSettings.getSettings());
        this.priorityThreshold = CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD.get(clusterSettings.getSettings());

        // Register listeners for dynamic updates
        clusterSettings.addSettingsUpdateConsumer(
            CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED,
            this::setPriorityAllocationEnabled
        );
        clusterSettings.addSettingsUpdateConsumer(
