 *
 * For each shard allocation attempt:
 * <ol>
 *   <li>If priority allocation is disabled, return {@link Decision#ALWAYS} (no constraints)</li>
 *   <li>Retrieve the index's priority level from its metadata</li>
 *   <li>Classify the target node as premium or standard tier</li>
 *   <li>Apply decision rules based on priority and tier:
 *     <ul>
 *       <li>High priority (>= threshold) on premium tier → {@link Decision#YES}</li>
 *       <li>High priority (>= threshold) on standard tier → {@link Decision#THROTTLE}
 *           (soft constraint; allow but prefer premium)</li>
 *       <li>Low priority (< threshold) on any tier → {@link Decision#YES}</li>
 *     </ul>
 *   </li>
 * </ol>
 * </p>
 *
 * <h2>Configuration</h2>
 *
 * Enable/disable the decider (cluster-level):
 * <pre>
 * cluster.routing.allocation.priority.enabled: true
 * </pre>
 *
 * Define premium tier node attributes:
 * <pre>
 * cluster.routing.allocation.priority.premium_tiers: [premium, hot]
 * </pre>
 *
 * Set priority threshold for soft constraints:
 * <pre>
 * cluster.routing.allocation.priority.threshold: 70
 * </pre>
 *
 * <h2>Index Configuration</h2>
 *
 * Set index priority (0-100, default 50):
 * <pre>
 * PUT /myindex/_settings
 * {
 *   "index.routing.allocation.priority": 100
 * }
 * </pre>
 *
 * Node tier classification (set in elasticsearch.yml or via node API):
 * <pre>
 * node.attr.allocation_tier: premium  # or "standard", "basic", etc.
 * </pre>
 *
 * <h2>Interaction with Other Deciders</h2>
 *
 * PriorityAllocationDecider is typically placed in the decider chain after:
 * <ul>
 *   <li>EnableAllocationDecider (check if allocation is enabled)</li>
 *   <li>DiskThresholdDecider (check if node has disk space)</li>
 *   <li>AwarenessAllocationDecider (check rack/zone constraints)</li>
 *   <li>FilterAllocationDecider (check include/exclude/require filters)</li>
 * </ul>
 *
 * This ensures that hard constraints (disk space, awareness) take precedence over
 * priority preferences.
 *
 * <h2>Examples</h2>
 *
 * <h3>Example 1: High-Priority Index Prefers Premium Nodes</h3>
 * <pre>
 * Cluster:
 *   - node-1: tier=premium (100MB free)
 *   - node-2: tier=standard (500MB free)
 *
 * Index: critical-app
 *   - priority=90
 *   - decision for node-1: YES (high priority + premium tier)
 *   - decision for node-2: THROTTLE (high priority + standard tier; suboptimal)
 *
 * Result: Shard allocates to node-1 (preferred)
 * </pre>
 *
 * <h3>Example 2: Low-Priority Index No Preference</h3>
 * <pre>
 * Index: cache-index
 *   - priority=10
 *   - decision for any node: YES (below threshold)
 *
 * Result: Shard allocates based on balanced allocation (no priority constraint)
 * </pre>
 *
 * <h3>Example 3: Degradation When Premium Nodes Full</h3>
 * <pre>
 * Cluster:
 *   - node-1: tier=premium (FULL - disk threshold breach)
 *   - node-2: tier=standard (500MB free)
 *
 * Index: critical-app
 *   - priority=90
 *   - decision for node-1: NO (DiskThresholdDecider blocks)
 *   - decision for node-2: THROTTLE (high priority but suboptimal tier)
 *
 * Result: Shard allocates to node-2 (graceful degradation)
 * </pre>
 *
 * @see PriorityShardsAllocator
 * @see AllocationDecider
 * @see Decision
 */
public class PriorityAllocationDecider extends AllocationDecider {

    private static final Logger logger = LogManager.getLogger(PriorityAllocationDecider.class);

    public static final String NAME = "priority_allocation";

    /**
     * Cluster-level setting to enable/disable priority-aware allocation constraints.
     * When disabled, this decider returns {@link Decision#ALWAYS} for all decisions.
     * Default: true
     */
    public static final Setting<Boolean> CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED = Setting.boolSetting(
        "cluster.routing.allocation.priority.enabled",
        true,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Cluster-level setting listing the node tier names considered "premium".
     * Nodes with the `allocation_tier` attribute matching one of these values
     * are classified as premium and receive priority preference for high-priority shards.
     * Default: ["premium"]
     *
     * Example:
     * <pre>
     * cluster.routing.allocation.priority.premium_tiers: [premium, hot]
     * </pre>
     */
    public static final Setting<List<String>> CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS = Setting.stringListSetting(
        "cluster.routing.allocation.priority.premium_tiers",
        java.util.List.of("premium"),
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Cluster-level setting specifying the priority threshold above which
     * the decider applies soft constraints (THROTTLE) for standard-tier nodes.
     * Shards from indices with priority >= this threshold prefer premium nodes,
     * but can still allocate to standard nodes (via THROTTLE decision).
     *
     * Range: 0-100
     * Default: 70
     *
     * Example:
     * <pre>
     * cluster.routing.allocation.priority.threshold: 70
     * </pre>
     */
    public static final Setting<Integer> CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD = Setting.intSetting(
        "cluster.routing.allocation.priority.threshold",
        70,
        0,
        100,
        Property.Dynamic,
        Property.NodeScope
    );

    // Volatile fields for dynamic configuration updates
    private volatile boolean priorityAllocationEnabled;
    private volatile List<String> premiumTiers;
    private volatile int priorityThreshold;

    /**
     * Creates a new PriorityAllocationDecider with default settings.
     */
    public PriorityAllocationDecider() {
        this.priorityAllocationEnabled = true;
        this.premiumTiers = java.util.List.of("premium");
        this.priorityThreshold = 70;
    }

    /**
     * Creates a new PriorityAllocationDecider with settings from the provided
     * configuration. Registers dynamic setting listeners for configuration updates.
     *
     * @param settings the node settings (unused; settings come from clusterSettings)
     * @param clusterSettings the cluster settings to watch for updates
     */
    public PriorityAllocationDecider(Settings settings, ClusterSettings clusterSettings) {
        // Initialize from cluster settings
        this.priorityAllocationEnabled = CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED.get(settings);
        this.premiumTiers = CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS.get(settings);
        this.priorityThreshold = CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD.get(settings);

        // Register listeners for dynamic updates
        clusterSettings.addSettingsUpdateConsumer(
            CLUSTER_ROUTING_ALLOCATION_PRIORITY_ENABLED,
            this::setPriorityAllocationEnabled
        );
        clusterSettings.addSettingsUpdateConsumer(
            CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS,
            this::setPremiumTiers
        );
        clusterSettings.addSettingsUpdateConsumer(
            CLUSTER_ROUTING_ALLOCATION_PRIORITY_THRESHOLD,
            this::setPriorityThreshold
        );
    }

    /**
     * Decides whether a shard can be allocated to a specific node.
     *
     * <p>
     * Decision logic:
     * <ul>
     *   <li>If priority allocation is disabled, return YES (always allow)</li>
     *   <li>Get index priority from metadata (default 50 if not set)</li>
     *   <li>Determine if node is premium tier</li>
     *   <li>Apply priority-based constraints:
     *     <ul>
     *       <li>If priority >= threshold AND node is premium: YES</li>
     *       <li>If priority >= threshold AND node is standard: THROTTLE (soft constraint)</li>
     *       <li>If priority < threshold: YES (no constraint)</li>
     *     </ul>
     *   </li>
     * </ul>
     * </p>
     *
     * @param shardRouting the shard being allocated
     * @param node the target node for allocation
     * @param allocation the current routing allocation state
     * @return the allocation decision (YES, THROTTLE, or NO)
     */
    @Override
    public Decision canAllocate(ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
        if (!priorityAllocationEnabled) {
            return Decision.ALWAYS; // Feature disabled; no constraints
        }

        // Extract index priority
        IndexMetadata indexMetadata = allocation.metadata().getIndexSafe(shardRouting.index());
        int indexPriority = getIndexPriority(indexMetadata);

        // Check if index priority warrants tier-based constraints
        if (indexPriority < priorityThreshold) {
            // Low priority; no constraint
            if (logger.isTraceEnabled()) {
                logger.trace(
                    "Shard [{}] has priority {} (below threshold {}); no priority-based constraint",
                    shardRouting.shardId(),
                    indexPriority,
                    priorityThreshold
                );
            }
            return Decision.ALWAYS;
        }

        // High priority; check node tier
        boolean isNodePremium = isNodePremiumTier(node, allocation);
        if (isNodePremium) {
            // Preferred allocation
            if (logger.isTraceEnabled()) {
                logger.trace(
                    "Shard [{}] has high priority {}; allocating to premium node [{}]",
                    shardRouting.shardId(),
                    indexPriority,
                    node.nodeId()
                );
            }
            return allocation.decision(
                Decision.YES,
                NAME,
                "shard [%s] has high priority [%d]; premium tier node [%s]",
                shardRouting.shardId(),
                indexPriority,
                node.nodeId()
            );
        } else {
            // Suboptimal allocation; allow with THROTTLE (soft constraint)
            if (logger.isTraceEnabled()) {
                logger.trace(
                    "Shard [{}] has high priority {} but standard node [{}]; throttling",
                    shardRouting.shardId(),
                    indexPriority,
                    node.nodeId()
                );
            }
            return allocation.decision(
                Decision.THROTTLE,
                NAME,
                "shard [%s] has high priority [%d]; standard tier node [%s] (prefer premium)",
                shardRouting.shardId(),
                indexPriority,
                node.nodeId()
            );
        }
    }

    /**
     * Decides whether a shard can remain on its current node.
     * Uses the same logic as canAllocate() since priority constraints apply equally.
     *
     * @param indexMetadata the index metadata
     * @param shardRouting the shard currently residing on the node
     * @param node the node where the shard currently resides
     * @param allocation the current routing allocation state
     * @return the allocation decision
     */
    @Override
    public Decision canRemain(
        IndexMetadata indexMetadata,
        ShardRouting shardRouting,
        RoutingNode node,
        RoutingAllocation allocation
    ) {
        // For residency decisions, use the same priority constraints as allocation
        // A high-priority shard may be encouraged to move to a premium node if
        // it's currently on a standard node (handled via rebalancing, not here)
        return canAllocate(shardRouting, node, allocation);
    }

    /**
     * Extracts the priority value for an index from its metadata.
     * Falls back to default priority if not explicitly set.
     *
     * @param indexMetadata the index metadata
     * @return the index priority (0-100), or default 50 if not set
     */
    private int getIndexPriority(IndexMetadata indexMetadata) {
        try {
            // TODO: Extract priority from index settings
            // Pseudo-code:
            // String priorityKey = PriorityShardsAllocator.INDEX_ROUTING_ALLOCATION_PRIORITY;
            // return indexMetadata.getSettings().getAsInt(priorityKey, 50);
            return 50; // placeholder
        } catch (Exception e) {
            logger.warn("Failed to retrieve priority for index [{}], using default", indexMetadata.getIndex().getName(), e);
            return 50; // default on error
        }
    }

    /**
     * Determines if a node is classified as a premium-tier node.
     * Checks the node's attributes for a tier classification and verifies
     * if it matches one of the configured premium tiers.
     *
     * @param node the routing node to check
     * @param allocation the routing allocation state (contains node metadata)
     * @return true if the node is classified as premium tier, false otherwise
     */
    private boolean isNodePremiumTier(RoutingNode node, RoutingAllocation allocation) {
        try {
            // TODO: Extract node tier attribute and check against premiumTiers
            // Pseudo-code:
            // var discoveryNode = allocation.nodes().get(node.nodeId());
            // if (discoveryNode == null) return false;
            // var nodeAttributes = discoveryNode.getAttributes();
            // String nodeTier = nodeAttributes.getOrDefault("allocation_tier", "standard");
            // return premiumTiers.contains(nodeTier);
            return false; // placeholder
        } catch (Exception e) {
            logger.warn("Failed to determine tier for node [{}], assuming standard", node.nodeId(), e);
            return false; // assume standard on error
        }
    }

    // ============= Configuration Update Methods =============

    /**
     * Called when the priority allocation enabled setting is updated dynamically.
     *
     * @param enabled the new enabled state
     */
    private void setPriorityAllocationEnabled(boolean enabled) {
        this.priorityAllocationEnabled = enabled;
        logger.info("Priority allocation decider is now {}", enabled ? "enabled" : "disabled");
    }

    /**
     * Called when the premium tiers setting is updated dynamically.
     *
     * @param tiers the new list of premium tier names
     */
    private void setPremiumTiers(List<String> tiers) {
        this.premiumTiers = tiers;
        logger.debug("Updated premium tier classifications: {}", tiers);
    }

    /**
     * Called when the priority threshold setting is updated dynamically.
     *
     * @param threshold the new priority threshold (0-100)
     */
    private void setPriorityThreshold(int threshold) {
        this.priorityThreshold = threshold;
        logger.debug("Updated priority threshold: {}", threshold);
    }

    // ============= Getters for testing/debugging =============

    /**
     * Returns whether priority allocation is currently enabled.
     *
     * @return true if enabled, false otherwise
     */
    public boolean isPriorityAllocationEnabled() {
        return priorityAllocationEnabled;
    }

    /**
     * Returns the current list of premium tier names.
     *
     * @return list of premium tier names
     */
    public List<String> getPremiumTiers() {
        return new java.util.ArrayList<>(premiumTiers);
    }

    /**
     * Returns the current priority threshold value.
     *
     * @return the priority threshold (0-100)
     */
    public int getPriorityThreshold() {
        return priorityThreshold;
    }
}

