     * </pre>
     */
    public static final Setting<List<String>> CLUSTER_ROUTING_ALLOCATION_PRIORITY_PREMIUM_TIERS = Setting.stringListSetting(
        "cluster.routing.allocation.priority.premium_tiers",
        java.util.List.of("premium"),
        Property.Dynamic,
        Property.NodeScope
